challenges.solution:
uniform vec2 u_resolution;
uniform float u_time;
out vec4 fragColor;

mat2 rotate2D(float angle) {
    float c = cos(angle);
    float s = sin(angle);
    return mat2(c, -s, s, c);
}

void main() {
    vec2 uv = gl_FragCoord.xy / u_resolution;
    vec2 p = uv - vec2(0.5);

    p = rotate2D(u_time) * p;

    float rect = step(abs(p.x), 0.3) * step(abs(p.y), 0.15);

    fragColor = vec4(rect, rect, rect, 1.0);
}

