challenges.template:
uniform vec2 u_resolution;
uniform float u_time;
out vec4 fragColor;

void main() {
    vec2 uv = gl_FragCoord.xy / u_resolution;
    vec2 p = uv - vec2(0.5);

    float r = length(p);
    float a = atan(p.y, p.x) + u_time * 0.2;

    // Fold into N=6 wedges
    float N = 6.0;
    float slice = 3.14159265 / N;  // half-wedge angle

    // Use mod to repeat the angle within each wedge
    a = mod(a, 2.0 * slice);

    // Mirror within the wedge (fold at the midpoint)
    a = /* abs(a - slice) */;

    // Reconstruct cartesian p from polar (r, a)
    p = /* vec2(cos(a), sin(a)) * r */;

    // Draw ring pattern in transformed space
    float ring = smoothstep(0.33, 0.31, r) - smoothstep(0.23, 0.21, r);
    float spot = smoothstep(0.11, 0.09, length(p - vec2(0.15, 0.0)));

    float shape = clamp(ring + spot, 0.0, 1.0);
    fragColor = vec4(shape, shape * 0.7, shape * 0.3, 1.0);
}

